override fun get(context: ResolutionContext): T {
    // Fast path: check if already created without locking
    if (!isCreated(context)) {
        KoinPlatformTools.synchronized(this) {
            // Double-check inside lock to avoid race condition
            if (!isCreated(context)) {
                value = create(context)
            }
        }
    }
    return getValue()
}

while (certificateBase < certificatesChainLength) {
    val certificateLength = readTripleByteLength()
    if (certificateLength > (certificatesChainLength - certificateBase)) {
        throw TLSException("Certificate length is too big")
    }
    if (certificateLength > remaining) throw TLSException("Certificate length is too big")

    val certificate = ByteArray(certificateLength)
    readFully(certificate)
    certificateBase += certificateLength + 3

    val x509 = factory.generateCertificate(certificate.inputStream())
    result.add(x509)
}

for ((key, value) in obj) {
  if (destination.containsKey(key) && destination[key] is MutableMap<*, *>) {
    // Objects: merge recursively
    val fieldDestination = destination[key] as MutableJsonMap
    val fieldMap = value as? JsonMap ?: error("'$key' is an object in destination but not in map")
    deepMergeObject(destination = fieldDestination, obj = fieldMap)
  } else {
    // Other types: add / overwrite
    destination[key] = value
  }
}

if (className in arrayTypeDefaultPatterns.keys) {
    val lambdaArgument = expression.valueArguments
        .mapNotNull { it.getArgumentExpression() }
        .filterIsInstance<KtLambdaExpression>()
        .firstOrNull()
        ?: return

    if (hasSideEffects(lambdaArgument)) return

    if (returnsDefaultValue(lambdaArgument, className)) {
        val message = "Unnecessary lambda builder returning default value. Use constructor without lambda."
        report(Finding(Entity.from(expression), message))
    }
}

if (condition is KtIsExpression) {
    val leftHandSide = condition.leftHandSide
    if (leftHandSide is KtNameReferenceExpression) {
        val identifier = leftHandSide.text
        val thenClause = expression.then
        val elseClause = expression.`else`
        val result = when (condition.isNegated) {
            true -> isIfElseNull(elseClause, thenClause, identifier)
            false -> isIfElseNull(thenClause, elseClause, identifier)
        }
        if (result) {
            addReport(expression)
        }
    }
}

if (singleStatement is KtBinaryExpression) {
    if (singleStatement.operationToken !in KtTokens.ALL_ASSIGNMENTS) return false

    // for an assignment expression only consider whether members on the LHS use the apply{} context
    singleStatement = singleStatement.left ?: return false
} else if (singleStatement !is KtThisExpression &&
    singleStatement !is KtReferenceExpression &&
    singleStatement !is KtDotQualifiedExpression
) {
    return false
}

while (stack.isNotEmpty()) {
    val current = stack.removeLast()

    // If the module is already in the set, that means we've already visited it, so we can skip it.
    if (!flatten.add(current)) {
        continue
    }

    // Add all the included modules to the stack if they haven't been visited yet.
    for (module in current.includedModules.asReversed()) {
        if (module !in flatten) {
            stack += module
        }
    }
}

internal fun SerialDescriptor.classDiscriminator(json: Json): String {
    // Plain loop is faster than allocation of Sequence or ArrayList
    // We can rely on the fact that only one JsonClassDiscriminator is present —
    // compiler plugin checked that.
    for (annotation in annotations) {
        if (annotation is JsonClassDiscriminator) return annotation.discriminator
    }
    return json.configuration.classDiscriminator
}

public data class ConstantParameterRouteSelector(
    val name: String,
    val value: String
) : RouteSelector() {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        if (context.call.parameters.contains(name, value)) {
            return RouteSelectorEvaluation.Constant
        }
        return RouteSelectorEvaluation.FailedParameter
    }

    override fun toString(): String = "[$name = $value]"
}

public data class HttpHeaderRouteSelector(
    override val name: String,
    val value: String
) : RouteSelector(), RouteParameterComponent {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        val headers = context.call.request.headers[name]
        val parsedHeaders = parseAndSortHeader(headers)
        val header = parsedHeaders.firstOrNull { it.value.equals(value, ignoreCase = true) }
            ?: return RouteSelectorEvaluation.FailedParameter

        return RouteSelectorEvaluation.Success(header.quality)
    }

    override fun toString(): String = "(header:$name = $value)"
}

public class RoutingRequest internal constructor(
    public val pathVariables: Parameters,
    internal val request: PipelineRequest,
    public override val call: RoutingCall
) : ApplicationRequest {

    public override val queryParameters: Parameters = request.queryParameters
    public override val rawQueryParameters: Parameters = request.rawQueryParameters
    public override val headers: Headers = request.headers
    public override val local: RequestConnectionPoint = request.local
    public override val cookies: RequestCookies = request.cookies

    override fun receiveChannel(): ByteReadChannel = request.receiveChannel()
}

try {
  val result = wrappedAdapter.fromJson(actualReader, customScalarAdapters)
  actualReader.endObject()
  return result
} catch (e: ApolloGraphQLException) {
  // There was an error. Consume the remaining entries of the object
  while (actualReader.hasNext()) {
    actualReader.nextName()
    actualReader.skipValue()
  }
  actualReader.endObject()
  throw e
}

when (val result = transformer.transform(this)) {
  is TransformResult.Delete -> null
  is TransformResult.Replace -> result.newNode
  is TransformResult.Continue -> {
    val newChildren = children.mapNotNull { it.transform(transformer) }
    val nodeContainer = NodeContainer(newChildren)
    copyWithNewChildrenInternal(nodeContainer).also {
      nodeContainer.assert()
    }
  }
}

for (index in parts.indices) {
    val (value, kind) = parts[index]
    val selector = when (kind) {
        RoutingPathSegmentKind.Parameter -> PathSegmentSelectorBuilder.parseParameter(value)
        RoutingPathSegmentKind.Constant -> PathSegmentSelectorBuilder.parseConstant(value)
    }
    // there may already be entry with same selector, so join them
    current = current.createChild(selector)
}

try {
    routingCallPipeline.execute(routingApplicationCall)
    if (!routingApplicationCall.isHandled) {
        routingApplicationCall.response.status()?.let { status ->
            routingApplicationCall.respond(status)
        }
    }
} catch (cause: Throwable) {
    routingCall.attributes.put(routingCallKey, routingCall)
    throw cause
} finally {
    application.monitor.raise(RoutingCallFinished, routingCall)
}

if (previousApplication != null) {
    safeRaiseEvent(ApplicationStopping, previousApplication)
    try {
        destroyBlocking(previousApplication, previousClassLoader)
    } catch (e: Throwable) {
        environment.log.error("Failed to destroy previous application instance.", e)
    }
    safeRaiseEvent(ApplicationStopped, previousApplication)
}

when (value) {
  is Ior.Left -> encodeSerializableElement(descriptor, 0, errorSerializer, value.value)
  is Ior.Right -> encodeSerializableElement(descriptor, 1, elementSerializer, value.value)
  is Ior.Both -> {
    encodeSerializableElement(descriptor, 0, errorSerializer, value.leftValue)
    encodeSerializableElement(descriptor, 1, elementSerializer, value.rightValue)
  }
}

try {
    onError(error)
} catch (errorHandlerException: Throwable) {
    errorHandlerException.throwIfFatal()
    printErrors("onError callback failed", error, errorHandlerException)

    try {
        reaktiveUncaughtErrorHandler(CompositeException(error, errorHandlerException))
    } catch (errorDeliveryException: Throwable) {
        errorDeliveryException.throwIfFatal()
        printErrors("Error delivering uncaught error", error, errorDeliveryException)
    }
}

if (transition is CrossfadeTransition) {
    return CrossfadePainter(
        start = previous.painter.takeIf { previous is AsyncImagePainter.State.Loading },
        end = current.painter,
        contentScale = contentScale,
        duration = transition.durationMillis.milliseconds,
        fadeStart = result !is SuccessResult || !result.isPlaceholderCached,
        preferExactIntrinsicSize = transition.preferExactIntrinsicSize,
        preferEndFirstIntrinsicSize = result.request.preferEndFirstIntrinsicSize,
    )
} else {
    return null
}

