        end = current.painter,
        contentScale = contentScale,
        duration = crossfadeMillis.milliseconds,
        fadeStart = !result.isPlaceholderCached,
        preferExactIntrinsicSize = false,
        preferEndFirstIntrinsicSize = result.request.preferEndFirstIntrinsicSize,
