if (complexity > allowedComplexity) {
    report(
        Finding(
            Entity.atName(function),
            "The function ${function.nameAsSafeName} appears to be too complex " +
                "based on Cognitive Complexity (complexity: $complexity). " +
                "Defined maximum allowed complexity for methods is set to '$allowedComplexity'"
        )
    )
}

if (complexity > allowedComplexity) {
    report(
        Finding(
            Entity.atName(function),
            "The function ${function.nameAsSafeName} appears to be too complex " +
                "based on Cyclomatic Complexity (complexity: $complexity). " +
                "The maximum allowed complexity for methods is set to '$allowedComplexity'"
        )
    )
}

if (parameterNumber > maximumAllowedParameter) {
    val parameterPrint = function.valueParameters.joinToString(separator = ", ") {
        it.nameAsSafeName.identifier + ": " + it.typeReference?.text
    }

    report(
        Finding(
            Entity.from(parameterList, function),
            "The $identifier($parameterPrint) has too many parameters. " +
                "The current maximum allowed parameters are $maximumAllowedParameter."
        )
    )
}

when (this) {
    is KtQualifiedExpression -> Entity.from(this.selectorExpression ?: this)

    is KtBinaryExpression -> {
        val rhs = this.right ?: return Entity.from(this)
        val operationSourceLocation = Location.from(operationReference).source
        val rhsSourceLocation = Location.from(rhs).endSource
        val textLocation = TextLocation(operationReference.startOffset, rhs.endOffset)
        Entity.from(
            this,
            Location(operationSourceLocation, rhsSourceLocation, textLocation, containingFile.absolutePath())
        )
    }

    else -> Entity.from(this)
}

if (classId != null) {
    Finding(
